import React from 'react';

function Result({ analysis, onBack }) {
  return (
    <div style={{ maxWidth: '700px', margin: '0 auto', padding: '20px' }}>
      <h2>Análisis del Candidato</h2>
      <div
        style={{
          backgroundColor: '#f5f5f5',
          padding: '15px',
          borderRadius: '10px',
          whiteSpace: 'pre-wrap',
          fontFamily: 'Arial, sans-serif',
        }}
      >
        {analysis}
      </div>
      <button
        onClick={onBack}
        style={{
          marginTop: '20px',
          padding: '10px 20px',
          backgroundColor: '#007bff',
          color: 'white',
          border: 'none',
          borderRadius: '8px',
          cursor: 'pointer',
        }}
      >
        Realizar otra evaluación
      </button>
    </div>
  );
}

export default Result;
